package com.example.documentviewer;

import android.app.Activity;
import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.text.TextUtils;
import android.util.Log;
import android.webkit.MimeTypeMap;
import android.widget.ImageView;
import android.widget.TextView;
import android.widget.Toast;

import java.io.File;
import java.io.InputStream;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

public class DocumentViewerActivity extends Activity {

    private static final String TAG = "DocumentViewerActivity";
    private static final Set<String> ALLOWED_MIME_TYPES = new HashSet<>(Arrays.asList(
            "application/pdf",
            "image/jpeg",
            "image/jpg",
            "image/png",
            "image/gif",
            "image/bmp",
            "image/webp"
    ));
    private static final Set<String> ALLOWED_EXTENSIONS = new HashSet<>(Arrays.asList(
            "pdf", "jpg", "jpeg", "png", "gif", "bmp", "webp"
    ));

    private TextView fileInfoTextView;
    private ImageView imageView;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_document_viewer);

        fileInfoTextView = findViewById(R.id.fileInfoTextView);
        imageView = findViewById(R.id.imageView);

        Intent intent = getIntent();
        if (intent != null && validateIntent(intent)) {
            handleIntent(intent);
        } else {
            showError("Invalid or unauthorized access");
            finish();
        }
    }

    private boolean validateIntent(Intent intent) {
        if (intent == null) {
            Log.w(TAG, "Intent is null");
            return false;
        }

        String action = intent.getAction();
        if (!Intent.ACTION_VIEW.equals(action)) {
            Log.w(TAG, "Invalid action: " + action);
            return false;
        }

        Uri uri = intent.getData();
        if (uri == null) {
            Log.w(TAG, "URI is null");
            return false;
        }

        if (!validateUri(uri)) {
            Log.w(TAG, "URI validation failed");
            return false;
        }

        String mimeType = intent.getType();
        if (!validateMimeType(mimeType, uri)) {
            Log.w(TAG, "MIME type validation failed: " + mimeType);
            return false;
        }

        if (!validateCaller()) {
            Log.w(TAG, "Caller validation failed");
            return false;
        }

        return true;
    }

    private boolean validateUri(Uri uri) {
        if (uri == null) {
            return false;
        }

        String scheme = uri.getScheme();
        if (scheme == null) {
            return false;
        }

        if (!scheme.equals("content") && !scheme.equals("file")) {
            Log.w(TAG, "Invalid URI scheme: " + scheme);
            return false;
        }

        String path = uri.getPath();
        if (TextUtils.isEmpty(path)) {
            return false;
        }

        if (path.contains("..")) {
            Log.w(TAG, "Path traversal attempt detected");
            return false;
        }

        return true;
    }

    private boolean validateMimeType(String mimeType, Uri uri) {
        if (!TextUtils.isEmpty(mimeType)) {
            String normalizedMimeType = mimeType.toLowerCase().trim();
            if (ALLOWED_MIME_TYPES.contains(normalizedMimeType)) {
                return true;
            }
        }

        String extension = getFileExtension(uri);
        if (!TextUtils.isEmpty(extension)) {
            String normalizedExtension = extension.toLowerCase().trim();
            if (ALLOWED_EXTENSIONS.contains(normalizedExtension)) {
                return true;
            }
        }

        return false;
    }

    private String getFileExtension(Uri uri) {
        String path = uri.getPath();
        if (TextUtils.isEmpty(path)) {
            return null;
        }

        int lastDot = path.lastIndexOf('.');
        if (lastDot > 0 && lastDot < path.length() - 1) {
            return path.substring(lastDot + 1);
        }

        return null;
    }

    private boolean validateCaller() {
        String callingPackage = getCallingPackage();
        
        if (callingPackage == null) {
            callingPackage = getReferrer() != null ? getReferrer().getHost() : null;
        }

        if (callingPackage == null) {
            Log.w(TAG, "Unable to determine calling package");
            return true;
        }

        if (callingPackage.equals(getPackageName())) {
            return true;
        }

        try {
            getPackageManager().getPackageInfo(callingPackage, 0);
            return true;
        } catch (Exception e) {
            Log.w(TAG, "Caller package not found: " + callingPackage);
            return false;
        }
    }

    private void handleIntent(Intent intent) {
        Uri uri = intent.getData();
        String mimeType = intent.getType();

        if (uri == null) {
            showError("No file URI provided");
            finish();
            return;
        }

        try {
            displayDocument(uri, mimeType);
        } catch (SecurityException e) {
            Log.e(TAG, "Security exception accessing file", e);
            showError("Permission denied to access file");
            finish();
        } catch (Exception e) {
            Log.e(TAG, "Error opening document", e);
            showError("Failed to open document");
            finish();
        }
    }

    private void displayDocument(Uri uri, String mimeType) {
        String fileName = getFileName(uri);
        String fileType = determineFileType(mimeType, uri);

        StringBuilder info = new StringBuilder();
        info.append("File: ").append(fileName != null ? fileName : "Unknown").append("\n");
        info.append("Type: ").append(fileType).append("\n");
        info.append("URI: ").append(uri.toString());

        fileInfoTextView.setText(info.toString());

        if (fileType.startsWith("image/")) {
            displayImage(uri);
        } else if (fileType.equals("application/pdf")) {
            displayPdf(uri);
        }
    }

    private String getFileName(Uri uri) {
        String path = uri.getPath();
        if (path != null) {
            int lastSlash = path.lastIndexOf('/');
            if (lastSlash >= 0 && lastSlash < path.length() - 1) {
                return path.substring(lastSlash + 1);
            }
        }
        return null;
    }

    private String determineFileType(String mimeType, Uri uri) {
        if (!TextUtils.isEmpty(mimeType)) {
            return mimeType;
        }

        String extension = getFileExtension(uri);
        if (!TextUtils.isEmpty(extension)) {
            String type = MimeTypeMap.getSingleton().getMimeTypeFromExtension(extension.toLowerCase());
            if (type != null) {
                return type;
            }
        }

        return "application/octet-stream";
    }

    private void displayImage(Uri uri) {
        try {
            imageView.setImageURI(uri);
            imageView.setVisibility(ImageView.VISIBLE);
        } catch (Exception e) {
            Log.e(TAG, "Error displaying image", e);
            showError("Failed to display image");
        }
    }

    private void displayPdf(Uri uri) {
        fileInfoTextView.append("\n\nPDF viewing requires additional implementation");
    }

    private void showError(String message) {
        Toast.makeText(this, message, Toast.LENGTH_LONG).show();
        Log.e(TAG, message);
    }
}